import { forwardRef, useId } from 'react';
import type { InputHTMLAttributes, SelectHTMLAttributes, TextareaHTMLAttributes } from 'react';
import { Button } from './Button';

type SharedProps = {
  label?: string;
  hint?: string;
  error?: string;
  id?: string;
};

type FieldInputProps = SharedProps & {
  as?: 'input' | undefined;
} & InputHTMLAttributes<HTMLInputElement>;

type FieldTextareaProps = SharedProps & {
  as: 'textarea';
} & TextareaHTMLAttributes<HTMLTextAreaElement>;

type FieldSelectProps = SharedProps & {
  as: 'select';
} & SelectHTMLAttributes<HTMLSelectElement>;

type FieldCheckboxProps = SharedProps & {
  as: 'checkbox';
} & Omit<InputHTMLAttributes<HTMLInputElement>, 'type'>;

type FieldFileButtonProps = SharedProps & {
  as: 'file-button';
  buttonLabel?: string;
  onFilesSelected?: (files: FileList | null) => void;
} & Omit<InputHTMLAttributes<HTMLInputElement>, 'type' | 'value' | 'onChange'>;

export type FieldProps =
  | FieldInputProps
  | FieldTextareaProps
  | FieldSelectProps
  | FieldCheckboxProps
  | FieldFileButtonProps;

export const Field = forwardRef<
  HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement,
  FieldProps
>(function Field(props, ref) {
  const generatedId = useId();
  const id = props.id ?? generatedId;
  const errorId = `${id}-error`;
  const hintId = `${id}-hint`;
  const describedBy = [props.error ? errorId : '', props.hint && !props.error ? hintId : '']
    .filter(Boolean)
    .join(' ') || undefined;

  if (props.as === 'textarea') {
    const { as, label, hint, error, id: _id, ...t } = props;
    void as;
    void label;
    void hint;
    void error;
    void _id;
    return (
      <>
        <textarea
          ref={ref as React.ForwardedRef<HTMLTextAreaElement>}
          id={id}
          aria-invalid={props.error ? true : undefined}
          aria-describedby={describedBy}
          {...t}
        />
        {props.error ? <small id={errorId}>{props.error}</small> : null}
        {props.hint && !props.error ? <small id={hintId}>{props.hint}</small> : null}
      </>
    );
  }

  if (props.as === 'select') {
    const { as, children, label, hint, error, id: _id, ...s } = props;
    void as;
    void label;
    void hint;
    void error;
    void _id;
    return (
      <>
        <select
          ref={ref as React.ForwardedRef<HTMLSelectElement>}
          id={id}
          aria-invalid={props.error ? true : undefined}
          aria-describedby={describedBy}
          {...s}
        >
          {children}
        </select>
        {props.error ? <small id={errorId}>{props.error}</small> : null}
        {props.hint && !props.error ? <small id={hintId}>{props.hint}</small> : null}
      </>
    );
  }

  if (props.as === 'checkbox') {
    const { as, label, hint, error, id: _id, ...c } = props;
    void as;
    void label;
    void hint;
    void error;
    void _id;
    return (
      <>
        <input
          ref={ref as React.ForwardedRef<HTMLInputElement>}
          id={id}
          type="checkbox"
          aria-invalid={props.error ? true : undefined}
          aria-describedby={describedBy}
          {...c}
        />
        {props.error ? <small id={errorId}>{props.error}</small> : null}
        {props.hint && !props.error ? <small id={hintId}>{props.hint}</small> : null}
      </>
    );
  }

  if (props.as === 'file-button') {
    const {
      as,
      buttonLabel = 'Choose files',
      onFilesSelected,
      className,
      label,
      hint,
      error,
      id: _id,
      ...f
    } = props;
    void as;
    void label;
    void hint;
    void error;
    void _id;
    return (
      <>
        <input
          ref={ref as React.ForwardedRef<HTMLInputElement>}
          id={id}
          type="file"
          style={{ display: 'none' }}
          aria-invalid={props.error ? true : undefined}
          aria-describedby={describedBy}
          onChange={(e) => {
            onFilesSelected?.(e.target.files);
            e.currentTarget.value = '';
          }}
          {...f}
        />
        <Button
          type="button"
          className={className}
          aria-controls={id}
          disabled={Boolean((f as InputHTMLAttributes<HTMLInputElement>).disabled)}
          onClick={(e) =>
            ((e.currentTarget.previousElementSibling as HTMLInputElement | null)?.click())
          }
        >
          <span>{buttonLabel}</span>
        </Button>
        {props.error ? <small id={errorId}>{props.error}</small> : null}
        {props.hint && !props.error ? <small id={hintId}>{props.hint}</small> : null}
      </>
    );
  }

  const { as, label, hint, error, id: _id, ...i } = props as FieldInputProps;
  void as;
  void label;
  void hint;
  void error;
  void _id;
  return (
    <>
      <input
        ref={ref as React.ForwardedRef<HTMLInputElement>}
        id={id}
        aria-invalid={props.error ? true : undefined}
        aria-describedby={describedBy}
        {...i}
      />
      {props.error ? <small id={errorId}>{props.error}</small> : null}
      {props.hint && !props.error ? <small id={hintId}>{props.hint}</small> : null}
    </>
  );
});

Field.displayName = 'Field';
